import{_ as c,C as d,o as i,c as u,a2 as n,b as r,w as t,a as s,E as o,a3 as l}from"./chunks/framework.B72_uj9U.js";const A=JSON.parse('{"title":"Junie CLI — Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"research/agents/junie-cli/architecture.md","filePath":"research/agents/junie-cli/architecture.md"}'),h={name:"research/agents/junie-cli/architecture.md"};function g(p,e,m,f,b,I){const a=d("Mermaid");return i(),u("div",null,[e[4]||(e[4]=n('<h1 id="junie-cli-—-architecture" tabindex="-1">Junie CLI — Architecture <a class="header-anchor" href="#junie-cli-—-architecture" aria-label="Permalink to &quot;Junie CLI — Architecture&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Junie&#39;s architecture is shaped by its origin as a JetBrains IDE plugin that was subsequently extended to operate as a standalone CLI agent. This dual heritage gives it a unique architectural profile: it carries the deep language intelligence of the IntelliJ Platform while adapting to the constraints and opportunities of terminal-based operation.</p><p>This document examines Junie&#39;s architecture across both modes, with particular attention to the multi-model routing system that is its key differentiator.</p><h2 id="high-level-architecture" tabindex="-1">High-Level Architecture <a class="header-anchor" href="#high-level-architecture" aria-label="Permalink to &quot;High-Level Architecture&quot;">​</a></h2>',5)),(i(),r(l,null,{default:t(()=>[o(a,{id:"mermaid-15",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20subgraph%20Presentation%5B%22Presentation%20Layer%22%5D%0A%20%20%20%20%20%20%20%20IDE%5B%22IDE%20Tool%20Window%5Cn(Swing%2FCompose)%22%5D%0A%20%20%20%20%20%20%20%20CLI%5B%22CLI%20Interface%5Cn(Terminal%20I%2FO)%22%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20Orchestration%5B%22Agent%20Orchestration%20Core%22%5D%0A%20%20%20%20%20%20%20%20PL%5BPlanner%5D%0A%20%20%20%20%20%20%20%20EX%5BExecutor%5D%0A%20%20%20%20%20%20%20%20VR%5BVerifier%5D%0A%20%20%20%20%20%20%20%20subgraph%20Router%5B%22Multi-Model%20Router%22%5D%0A%20%20%20%20%20%20%20%20%20%20%20%20Claude%5BClaude%5D%0A%20%20%20%20%20%20%20%20%20%20%20%20GPT%5BGPT%5D%0A%20%20%20%20%20%20%20%20%20%20%20%20Gemini%5BGemini%5D%0A%20%20%20%20%20%20%20%20end%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20Tools%5B%22Tool%20Execution%20Layer%22%5D%0A%20%20%20%20%20%20%20%20IDETools%5B%22IDE%20Mode%3A%20PSI%20Tree%2C%20Inspections%2C%5CnRefactoring%20Engine%2C%20Test%20Runners%2C%5CnDebugger%2C%20Build%20System%20API%22%5D%0A%20%20%20%20%20%20%20%20CLITools%5B%22CLI%20Mode%3A%20File%20System%20I%2FO%2C%5CnShell%20Execution%2C%20Process%20Management%2C%5CnTest%20Execution%2C%20Build%20Commands%2C%20Git%22%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20Backend%5B%22JetBrains%20Backend%20Services%22%5D%0A%20%20%20%20%20%20%20%20Auth%5B%22Authentication%20%26%20License%20Validation%22%5D%0A%20%20%20%20%20%20%20%20Proxy%5B%22Model%20API%20Proxying%22%5D%0A%20%20%20%20%20%20%20%20Usage%5B%22Usage%20Tracking%20%26%20Rate%20Limiting%22%5D%0A%20%20%20%20%20%20%20%20Telemetry%5B%22Telemetry%20%26%20Analytics%22%5D%0A%20%20%20%20end%0A%0A%20%20%20%20IDE%20%26%20CLI%20--%3E%20Orchestration%0A%20%20%20%20Orchestration%20--%3E%20Tools%0A%20%20%20%20Tools%20--%3E%20Backend%0A"})]),fallback:t(()=>[...e[0]||(e[0]=[s(" Loading... ",-1)])]),_:1})),e[5]||(e[5]=n(`<h2 id="ide-plugin-architecture" tabindex="-1">IDE Plugin Architecture <a class="header-anchor" href="#ide-plugin-architecture" aria-label="Permalink to &quot;IDE Plugin Architecture&quot;">​</a></h2><h3 id="intellij-platform-integration" tabindex="-1">IntelliJ Platform Integration <a class="header-anchor" href="#intellij-platform-integration" aria-label="Permalink to &quot;IntelliJ Platform Integration&quot;">​</a></h3><p>Junie&#39;s IDE mode is built on the IntelliJ Platform, which provides the richest code analysis infrastructure in the industry. Key integration points include:</p><h4 id="psi-program-structure-interface" tabindex="-1">PSI (Program Structure Interface) <a class="header-anchor" href="#psi-program-structure-interface" aria-label="Permalink to &quot;PSI (Program Structure Interface)&quot;">​</a></h4><p>The PSI is JetBrains&#39; abstract syntax tree representation, and it is the foundation of all code intelligence in JetBrains IDEs:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Source Code → Lexer → Parser → PSI Tree → Semantic Analysis</span></span>
<span class="line"><span>                                   │</span></span>
<span class="line"><span>                                   ├── Type Resolution</span></span>
<span class="line"><span>                                   ├── Reference Resolution</span></span>
<span class="line"><span>                                   ├── Control Flow Analysis</span></span>
<span class="line"><span>                                   └── Data Flow Analysis</span></span></code></pre></div><p>When Junie operates in IDE mode, it has access to:</p><ul><li><strong>Fully resolved type information</strong> for all expressions and declarations</li><li><strong>Cross-file reference resolution</strong> (find usages, go to definition)</li><li><strong>Import graph</strong> showing dependencies between files and modules</li><li><strong>Inheritance hierarchies</strong> and interface implementations</li><li><strong>Call graphs</strong> showing how functions invoke each other</li><li><strong>Data flow analysis</strong> tracking how values propagate through code</li></ul><p>This gives IDE-mode Junie a level of code understanding that is simply unavailable to terminal-based agents that rely on text-level analysis.</p><h4 id="inspections-system" tabindex="-1">Inspections System <a class="header-anchor" href="#inspections-system" aria-label="Permalink to &quot;Inspections System&quot;">​</a></h4><p>JetBrains IDEs run hundreds of code inspections in real-time:</p><ul><li><strong>Code quality</strong>: Unused variables, unreachable code, redundant operations</li><li><strong>Potential bugs</strong>: Null pointer dereferences, type mismatches, resource leaks</li><li><strong>Performance</strong>: Inefficient algorithms, unnecessary allocations</li><li><strong>Style</strong>: Naming conventions, formatting, idiomatic patterns</li><li><strong>Framework-specific</strong>: Spring annotations, React hook rules, Django patterns</li></ul><p>In IDE mode, Junie can query these inspections to:</p><ol><li>Understand existing code quality issues before making changes</li><li>Verify that its changes don&#39;t introduce new warnings</li><li>Use quick-fix suggestions as guidance for code modifications</li></ol><h4 id="refactoring-engine" tabindex="-1">Refactoring Engine <a class="header-anchor" href="#refactoring-engine" aria-label="Permalink to &quot;Refactoring Engine&quot;">​</a></h4><p>The IntelliJ refactoring engine performs semantic-aware code transformations:</p><ul><li><strong>Rename</strong>: Updates all references across the project, including strings and comments</li><li><strong>Extract Method/Variable/Constant</strong>: Identifies scope, parameters, and return types</li><li><strong>Inline</strong>: Replaces a symbol with its definition, handling all usage sites</li><li><strong>Move</strong>: Relocates classes/functions with import updates</li><li><strong>Change Signature</strong>: Modifies function parameters with call-site updates</li></ul><p>These refactorings are semantically correct — they understand the language&#39;s scoping rules, type system, and import mechanisms. When Junie uses them in IDE mode, it gets guaranteed-correct transformations that would be risky to perform with text-based find-and-replace.</p><h4 id="test-runner-integration" tabindex="-1">Test Runner Integration <a class="header-anchor" href="#test-runner-integration" aria-label="Permalink to &quot;Test Runner Integration&quot;">​</a></h4><p>JetBrains IDEs have first-class test runner support:</p><ul><li><strong>JUnit/TestNG</strong> (Java/Kotlin)</li><li><strong>pytest/unittest</strong> (Python)</li><li><strong>Jest/Mocha/Vitest</strong> (JavaScript/TypeScript)</li><li><strong>RSpec/Minitest</strong> (Ruby)</li><li><strong>Go test</strong> (Go)</li><li><strong>NUnit/xUnit</strong> (.NET)</li></ul><p>In IDE mode, Junie receives structured test results:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>TestResult {</span></span>
<span class="line"><span>  name: &quot;test_user_creation&quot;</span></span>
<span class="line"><span>  status: FAILED</span></span>
<span class="line"><span>  duration: 0.45s</span></span>
<span class="line"><span>  assertion_error: &quot;Expected 201, got 400&quot;</span></span>
<span class="line"><span>  stack_trace: [...]</span></span>
<span class="line"><span>  source_location: &quot;tests/test_user.py:42&quot;</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>This structured output is richer than raw terminal test output and allows Junie to more precisely diagnose and fix test failures.</p><h3 id="plugin-registration" tabindex="-1">Plugin Registration <a class="header-anchor" href="#plugin-registration" aria-label="Permalink to &quot;Plugin Registration&quot;">​</a></h3><p>As an IntelliJ plugin, Junie registers itself through the standard plugin mechanism:</p><ul><li><strong>Tool Window Factory</strong>: Creates the Junie panel in the IDE sidebar</li><li><strong>Action Registration</strong>: Adds menu items and keyboard shortcuts</li><li><strong>Service Registration</strong>: Background services for agent orchestration</li><li><strong>Listener Registration</strong>: Responds to file changes, build events, test results</li><li><strong>Extension Points</strong>: Hooks into existing IDE functionality</li></ul><h2 id="cli-mode-architecture" tabindex="-1">CLI Mode Architecture <a class="header-anchor" href="#cli-mode-architecture" aria-label="Permalink to &quot;CLI Mode Architecture&quot;">​</a></h2><h3 id="installation-and-setup" tabindex="-1">Installation and Setup <a class="header-anchor" href="#installation-and-setup" aria-label="Permalink to &quot;Installation and Setup&quot;">​</a></h3><p>The CLI mode is distributed through:</p><ol><li><strong>JetBrains Toolbox</strong>: The standard JetBrains tool management application</li><li><strong>Standalone Installer</strong>: Direct download for terminal-only usage</li><li><strong>Package Managers</strong>: Likely available via brew, apt, etc.</li></ol><h3 id="runtime-structure" tabindex="-1">Runtime Structure <a class="header-anchor" href="#runtime-structure" aria-label="Permalink to &quot;Runtime Structure&quot;">​</a></h3><p>In CLI mode, Junie operates as a standalone process:</p>`,33)),(i(),r(l,null,{default:t(()=>[o(a,{id:"mermaid-269",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20TIO%5B%22Terminal%20I%2FO%20Layer%5Cn(stdin%2Fstdout%2Fstderr)%22%5D%0A%20%20%20%20TIO%20--%3E%20ACL%5B%22Agent%20Core%20Logic%5Cn(same%20as%20IDE%20mode)%22%5D%0A%20%20%20%20ACL%20--%3E%20TL%5B%22Tool%20Implementations%5Cn(File%20Read%2FWrite%2C%20Shell%20Execution%2C%5CnGit%20Operations%2C%20Project%20Analysis%2C%5CnCode%20Search)%22%5D%0A%20%20%20%20TL%20--%3E%20API%5B%22JetBrains%20API%20Client%5Cn(HTTPS%20to%20backend)%22%5D%0A"})]),fallback:t(()=>[...e[1]||(e[1]=[s(" Loading... ",-1)])]),_:1})),e[6]||(e[6]=n('<h3 id="ide-knowledge-without-the-ide" tabindex="-1">IDE Knowledge Without the IDE <a class="header-anchor" href="#ide-knowledge-without-the-ide" aria-label="Permalink to &quot;IDE Knowledge Without the IDE&quot;">​</a></h3><p>A critical architectural question is: how much of the IDE&#39;s intelligence transfers to CLI mode? Based on observable behavior and JetBrains&#39; documentation:</p><p><strong>Transfers to CLI mode:</strong></p><ul><li>Project structure understanding (from build files, directory layout)</li><li>Build system knowledge (Maven, Gradle, npm, pip, cargo command invocation)</li><li>Test framework awareness (knows how to run and parse test output)</li><li>Language-specific heuristics (common patterns, idioms, error patterns)</li><li>Multi-file refactoring logic (though without PSI, it&#39;s text-based)</li><li>Git integration for change tracking and history</li></ul><p><strong>Lost in CLI mode:</strong></p><ul><li>Real-time PSI tree analysis (requires the IDE&#39;s language engine)</li><li>Live inspection results (requires IDE background analysis)</li><li>Semantic refactoring guarantees (falls back to text-based operations)</li><li>Debugger integration (no IDE debugger available)</li><li>Rich test result parsing (gets terminal output instead of structured data)</li><li>Real-time compiler error feedback</li></ul><p><strong>Partially preserved:</strong></p><ul><li>Type understanding (LLM can infer types, but without PSI guarantees)</li><li>Import management (can analyze imports textually, not semantically)</li><li>Code navigation (can grep/search, but not &quot;go to definition&quot; semantically)</li></ul><h2 id="multi-model-routing-system" tabindex="-1">Multi-Model Routing System <a class="header-anchor" href="#multi-model-routing-system" aria-label="Permalink to &quot;Multi-Model Routing System&quot;">​</a></h2><h3 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h3><p>The multi-model routing system is Junie&#39;s most distinctive architectural feature. Rather than using a single LLM for all tasks, Junie dynamically selects the best model for each sub-task:</p>',11)),(i(),r(l,null,{default:t(()=>[o(a,{id:"mermaid-375",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20IN%5B%22Input%3A%20Agent%20sub-task%20%2B%20context%22%5D%20--%3E%20CL%7BClassify%20task%7D%0A%20%20%20%20CL%20--%3E%7Ccomplex%20reasoning%7C%20M1%5B%22Claude%20Sonnet%2FOpus%22%5D%0A%20%20%20%20CL%20--%3E%7Cfast%20edit%7C%20M2%5B%22Gemini%20Flash%22%5D%0A%20%20%20%20CL%20--%3E%7Ccode%20generation%7C%20M3%5B%22Best%20model%20for%20language%2Fdomain%22%5D%0A%20%20%20%20CL%20--%3E%7Cplanning%7C%20M4%5B%22Reasoning%20model%22%5D%0A%20%20%20%20M1%20%26%20M2%20%26%20M3%20%26%20M4%20--%3E%20OUT%5B%22Model%20selection%20%2B%20parameters%22%5D%0A"})]),fallback:t(()=>[...e[2]||(e[2]=[s(" Loading... ",-1)])]),_:1})),e[7]||(e[7]=n('<h3 id="routing-dimensions" tabindex="-1">Routing Dimensions <a class="header-anchor" href="#routing-dimensions" aria-label="Permalink to &quot;Routing Dimensions&quot;">​</a></h3><p>The router likely considers multiple dimensions:</p><ol><li><strong>Task type</strong>: Planning, editing, analysis, test interpretation, code generation</li><li><strong>Complexity</strong>: Simple one-liner vs. complex multi-file change</li><li><strong>Language</strong>: Some models are better at certain languages</li><li><strong>Latency requirements</strong>: Interactive queries need fast responses</li><li><strong>Cost optimization</strong>: Use cheaper models when quality permits</li><li><strong>Context size</strong>: Some tasks need large context windows</li></ol><h3 id="evidence-from-benchmarks" tabindex="-1">Evidence from Benchmarks <a class="header-anchor" href="#evidence-from-benchmarks" aria-label="Permalink to &quot;Evidence from Benchmarks&quot;">​</a></h3><p>The Terminal-Bench 2.0 results provide concrete evidence of multi-model benefits:</p><table tabindex="0"><thead><tr><th>Configuration</th><th>Score</th><th>Rank</th></tr></thead><tbody><tr><td>Junie (Multiple Models)</td><td>71.0%</td><td>#14</td></tr><tr><td>Junie (Gemini 3 Flash)</td><td>64.3%</td><td>#25</td></tr></tbody></table><p>The <strong>6.7 percentage point uplift</strong> (71.0% vs 64.3%) from multi-model routing is substantial. This means that for roughly 1 in 15 tasks, the model routing made the difference between success and failure.</p><h3 id="jetbrains-as-orchestration-layer" tabindex="-1">JetBrains as Orchestration Layer <a class="header-anchor" href="#jetbrains-as-orchestration-layer" aria-label="Permalink to &quot;JetBrains as Orchestration Layer&quot;">​</a></h3><p>JetBrains acts as the intermediary between Junie and LLM providers:</p>',9)),(i(),r(l,null,{default:t(()=>[o(a,{id:"mermaid-468",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20JA%5B%22Junie%20Agent%22%5D%20--%3E%20JB%5B%22JetBrains%20Backend%22%5D%0A%20%20%20%20JB%20--%3E%20CA%5B%22Claude%20API%22%5D%0A%20%20%20%20JB%20--%3E%20OA%5B%22OpenAI%20API%22%5D%0A%20%20%20%20JB%20--%3E%20GA%5B%22Google%20AI%20API%22%5D%0A"})]),fallback:t(()=>[...e[3]||(e[3]=[s(" Loading... ",-1)])]),_:1})),e[8]||(e[8]=n('<p>This architecture provides:</p><ul><li><strong>Single authentication</strong>: Users authenticate with JetBrains, not each provider</li><li><strong>Unified billing</strong>: Subscription covers all model usage</li><li><strong>Model abstraction</strong>: JetBrains can swap or update models transparently</li><li><strong>Quality control</strong>: JetBrains can A/B test model routing strategies</li><li><strong>Rate limiting</strong>: Centralized management of API quotas</li></ul><h2 id="communication-protocol" tabindex="-1">Communication Protocol <a class="header-anchor" href="#communication-protocol" aria-label="Permalink to &quot;Communication Protocol&quot;">​</a></h2><h3 id="ide-mode-communication" tabindex="-1">IDE Mode Communication <a class="header-anchor" href="#ide-mode-communication" aria-label="Permalink to &quot;IDE Mode Communication&quot;">​</a></h3><p>In IDE mode, Junie communicates through the IntelliJ Platform&#39;s internal APIs:</p><ul><li><strong>Direct API calls</strong> to PSI, inspection, and refactoring services</li><li><strong>Message bus</strong> for event-driven communication (file changes, build results)</li><li><strong>Service layer</strong> for background task management</li></ul><h3 id="cli-mode-communication" tabindex="-1">CLI Mode Communication <a class="header-anchor" href="#cli-mode-communication" aria-label="Permalink to &quot;CLI Mode Communication&quot;">​</a></h3><p>In CLI mode, communication is structured differently:</p><ul><li><strong>HTTPS</strong> to JetBrains backend for model inference</li><li><strong>Local file I/O</strong> for reading and writing project files</li><li><strong>Process spawning</strong> for shell command execution</li><li><strong>Standard streams</strong> (stdin/stdout/stderr) for user interaction</li></ul><h3 id="backend-protocol" tabindex="-1">Backend Protocol <a class="header-anchor" href="#backend-protocol" aria-label="Permalink to &quot;Backend Protocol&quot;">​</a></h3><p>The JetBrains backend likely uses a streaming protocol for model communication:</p><ul><li>Server-Sent Events (SSE) or WebSocket for streaming responses</li><li>JSON-based request/response format</li><li>Authentication via JetBrains account tokens</li><li>Session management for conversation continuity</li></ul><h2 id="security-architecture" tabindex="-1">Security Architecture <a class="header-anchor" href="#security-architecture" aria-label="Permalink to &quot;Security Architecture&quot;">​</a></h2><h3 id="authentication" tabindex="-1">Authentication <a class="header-anchor" href="#authentication" aria-label="Permalink to &quot;Authentication&quot;">​</a></h3><ul><li>JetBrains account-based authentication</li><li>License validation (AI Pro or AI Ultimate required)</li><li>Token-based session management</li><li>No direct API key management needed by users</li></ul><h3 id="permissions-model" tabindex="-1">Permissions Model <a class="header-anchor" href="#permissions-model" aria-label="Permalink to &quot;Permissions Model&quot;">​</a></h3><p>Junie implements a permission system for sensitive operations:</p><ul><li><strong>File modifications</strong>: May require user approval depending on configuration</li><li><strong>Shell commands</strong>: Likely has an allowlist/blocklist system</li><li><strong>Network access</strong>: Controlled through the JetBrains backend proxy</li><li><strong>Destructive operations</strong>: Additional confirmation required</li></ul><h3 id="data-handling" tabindex="-1">Data Handling <a class="header-anchor" href="#data-handling" aria-label="Permalink to &quot;Data Handling&quot;">​</a></h3><ul><li>Code sent to LLM providers through JetBrains&#39; proxy</li><li>Subject to JetBrains&#39; data processing agreements</li><li>Enterprise customers may have data residency options</li><li>Telemetry collection governed by JetBrains privacy policy</li></ul><h2 id="comparison-with-other-agent-architectures" tabindex="-1">Comparison with Other Agent Architectures <a class="header-anchor" href="#comparison-with-other-agent-architectures" aria-label="Permalink to &quot;Comparison with Other Agent Architectures&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Aspect</th><th>Junie</th><th>Claude Code</th><th>Aider</th><th>Codex CLI</th></tr></thead><tbody><tr><td>Runtime</td><td>JVM (IDE) / Native (CLI)</td><td>Node.js</td><td>Python</td><td>Node.js</td></tr><tr><td>Model Access</td><td>JetBrains proxy</td><td>Direct Anthropic API</td><td>Direct multi-provider</td><td>Direct OpenAI API</td></tr><tr><td>Code Analysis</td><td>PSI (IDE) / Heuristic (CLI)</td><td>File-based</td><td>File-based</td><td>File-based</td></tr><tr><td>Extension Model</td><td>IDE plugins</td><td>MCP servers</td><td>—</td><td>—</td></tr><tr><td>State Management</td><td>Server + Local</td><td>Local</td><td>Local (git)</td><td>Local</td></tr><tr><td>Streaming</td><td>Yes (SSE/WebSocket)</td><td>Yes (SSE)</td><td>Yes</td><td>Yes</td></tr></tbody></table><h2 id="key-architectural-insights" tabindex="-1">Key Architectural Insights <a class="header-anchor" href="#key-architectural-insights" aria-label="Permalink to &quot;Key Architectural Insights&quot;">​</a></h2><ol><li><p><strong>IDE-first design is both strength and limitation</strong>: The deep IDE integration gives Junie unmatched code intelligence in IDE mode, but some of this is necessarily lost in CLI mode. The architecture must gracefully degrade.</p></li><li><p><strong>Multi-model routing is a genuine innovation</strong>: By abstracting the model layer, JetBrains can optimize model selection independently of the agent logic, creating a feedback loop for continuous improvement.</p></li><li><p><strong>Server dependency is a trade-off</strong>: The JetBrains backend provides unified auth, billing, and model routing, but also means Junie cannot operate offline or without JetBrains infrastructure.</p></li><li><p><strong>The proxy architecture enables unique capabilities</strong>: By routing all model requests through their servers, JetBrains can implement sophisticated caching, routing, and optimization strategies invisible to the agent itself.</p></li></ol>',24))])}const C=c(h,[["render",g]]);export{A as __pageData,C as default};
